/// Sanitizer that redacts sensitive data from maps and strings
class LogSanitizer {
  const LogSanitizer();

  /// Sanitize an arbitrary map (headers, body, params, etc.)
  Map<String, dynamic> sanitizeMap(Map<String, dynamic>? input) {
    if (input == null) return {};
    return input.map((key, value) => MapEntry(key, _sanitizeEntry(key, value)));
  }

  /// Sanitize HTTP headers specifically
  Map<String, String> sanitizeHeaders(Map<String, String>? headers) {
    if (headers == null) return {};
    return headers.map(
      (key, value) => MapEntry(key, _sanitizeEntry(key, value).toString()),
    );
  }

  dynamic _sanitizeEntry(String key, dynamic value) {
    final lowerKey = key.toLowerCase().replaceAll('-', '_').replaceAll(' ', '_');

    // Fully redact
    if (SensitiveFields.fullyRedacted.contains(lowerKey)) {
      return '[REDACTED]';
    }

    // Partially mask (show type + last 4 chars)
    if (SensitiveFields.partiallyMasked.contains(lowerKey)) {
      return _mask(value?.toString());
    }

    // PII masking
    if (SensitiveFields.piiFields.contains(lowerKey)) {
      return _maskPii(value?.toString());
    }

    // Recurse into nested maps
    if (value is Map<String, dynamic>) {
      return sanitizeMap(value);
    }

    if (value is Map) {
      return sanitizeMap(
        value.map((k, v) => MapEntry(k.toString(), v)),
      );
    }

    // Recurse into lists
    if (value is List) {
      return value.map((item) {
        if (item is Map<String, dynamic>) return sanitizeMap(item);
        return item;
      }).toList();
    }

    return value;
  }

  /// Mask a value showing only its length and last 4 characters
  String _mask(String? value) {
    if (value == null || value.isEmpty) return '[REDACTED]';
    if (value.length <= 4) return '[REDACTED]';
    return '***${value.substring(value.length - 4)} (len:${value.length})';
  }

  /// Mask PII: e.g., "john@example.com" → "j***@e***.com"
  String _maskPii(String? value) {
    if (value == null || value.isEmpty) return '[REDACTED-PII]';

    // Email pattern
    if (value.contains('@')) {
      final parts = value.split('@');
      if (parts.length == 2) {
        final local = parts[0];
        final domain = parts[1];
        final maskedLocal =
            local.isNotEmpty ? '${local[0]}***' : '***';
        final domainParts = domain.split('.');
        final maskedDomain = domainParts.isNotEmpty
            ? '${domainParts[0][0]}***.${domainParts.length > 1 ? domainParts.last : '***'}'
            : '***';
        return '$maskedLocal@$maskedDomain';
      }
    }

    // Generic PII: show first and last char
    if (value.length <= 2) return '[REDACTED-PII]';
    return '${value[0]}${'*' * (value.length - 2)}${value[value.length - 1]}';
  }
}

/// Sink interface for log output destinations
abstract class LogSink {
  Future<void> write(LogEntry entry);
  Future<void> flush();
}

/// Console sink — only active in debug/profile builds
class ConsoleLogSink implements LogSink {
  @override
  Future<void> write(LogEntry entry) async {
    // SECURITY: Never print to console in release builds
    if (kReleaseMode) return;

    final prefix = '[${entry.level.name.toUpperCase()}][${entry.category.name}]';
    final line = '$prefix ${entry.timestamp.toIso8601String()} ${entry.message}';

    // Use debugPrint for safe output (handles long strings, throttles)
    debugPrint(line);
    if (entry.metadata != null && entry.metadata!.isNotEmpty) {
      debugPrint('  meta: ${jsonEncode(entry.metadata)}');
    }
  }

  @override
  Future<void> flush() async {}
}

/// In-memory ring buffer sink for crash reports (limited size, auto-evicts)
class RingBufferLogSink implements LogSink {
  final int maxEntries;
  final List<LogEntry> _buffer = [];

  RingBufferLogSink({this.maxEntries = 200});

  @override
  Future<void> write(LogEntry entry) async {
    _buffer.add(entry);
    if (_buffer.length > maxEntries) {
      _buffer.removeAt(0);
    }
  }

  @override
  Future<void> flush() async {
    _buffer.clear();
  }

  /// Get recent entries for crash report attachment
  List<Map<String, dynamic>> getRecentEntries({int count = 50}) {
    final start = (_buffer.length - count).clamp(0, _buffer.length);
    return _buffer.sublist(start).map((e) => e.toJson()).toList();
  }
}

