/// Main production logger — singleton
class AppLogger {
  static AppLogger? _instance;

  final LogSanitizer _sanitizer;
  final List<LogSink> _sinks;
  final LogLevel _minLevel;

  AppLogger._({
    required LogLevel minLevel,
    required List<LogSink> sinks,
  })  : _minLevel = minLevel,
        _sinks = sinks,
        _sanitizer = const LogSanitizer();

  /// Initialize the logger. Call once at app startup.
  static void initialize({
    LogLevel? minLevel,
    List<LogSink>? sinks,
  }) {
    // In release mode, minimum level is INFO regardless of what's requested
    final effectiveLevel = kReleaseMode
        ? LogLevel.info
        : (minLevel ?? LogLevel.debug);

    final effectiveSinks = sinks ??
        [
          ConsoleLogSink(),
          RingBufferLogSink(),
          // In production, add: RemoteLogSink(endpoint: '...')
        ];

    _instance = AppLogger._(
      minLevel: effectiveLevel,
      sinks: effectiveSinks,
    );
  }

  static AppLogger get instance {
    if (_instance == null) {
      initialize();
    }
    return _instance!;
  }

  /// Core log method
  void _log(
    LogLevel level,
    LogCategory category,
    String message, {
    Map<String, dynamic>? metadata,
    String? correlationId,
  }) {
    if (level.index < _minLevel.index) return;

    // Sanitize any metadata before it reaches any sink
    final sanitizedMeta =
        metadata != null ? _sanitizer.sanitizeMap(metadata) : null;

    final entry = LogEntry(
      level: level,
      category: category,
      message: message,
      metadata: sanitizedMeta,
      correlationId: correlationId,
    );

    for (final sink in _sinks) {
      sink.write(entry);
    }
  }

  // ---------------------------------------------------------------------------
  // HTTP Logging
  // ---------------------------------------------------------------------------

  /// Log an outgoing HTTP request
  void logHttpRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    dynamic body,
    String? correlationId,
  }) {
    // Sanitize the URL to remove query params that might contain tokens
    final sanitizedUrl = _sanitizeUrl(url);

    final meta = <String, dynamic>{
      'method': method,
      'url': sanitizedUrl,
    };

    if (headers != null) {
      meta['headers'] = _sanitizer.sanitizeHeaders(headers);
    }

    // Only log body shape, not full content (may contain PII/secrets)
    if (body != null) {
      meta['body_type'] = body.runtimeType.toString();
      if (body is Map) {
        meta['body_keys'] = (body as Map).keys.toList();
        // Sanitize body values
        meta['body'] = _sanitizer.sanitizeMap(
          body.map((k, v) => MapEntry(k.toString(), v)),
        );
      } else if (body is String) {
        meta['body_length'] = body.length;
        // Do NOT log raw string bodies — they may contain anything
      }
    }

    _log(
      LogLevel.info,
      LogCategory.http,
      'HTTP $method → $sanitizedUrl',
      metadata: meta,
      correlationId: correlationId,
    );
  }

  /// Log an HTTP response
  void logHttpResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    dynamic body,
    Duration? duration,
    String? correlationId,
  }) {
    final sanitizedUrl = _sanitizeUrl(url);
    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.info;

    final meta = <String, dynamic>{
      'method': method,
      'url': sanitizedUrl,
      'status': statusCode,
    };

    if (duration != null) {
      meta['duration_ms'] = duration.inMilliseconds;
    }

    if (headers != null) {
      meta['headers'] = _sanitizer.sanitizeHeaders(headers);
    }

    // For error responses, log sanitized body to help debugging
    if (statusCode >= 400 && body != null) {
      if (body is Map) {
        meta['error_body'] = _sanitizer.sanitizeMap(
          body.map((k, v) => MapEntry(k.toString(), v)),
        );
      } else if (body is String) {
        // Only log first 200 chars of error message, sanitized
        meta['error_body_preview'] =
            body.length > 200 ? '${body.substring(0, 200)}...' : body;
      }
    }

    _log(
      level,
      LogCategory.http,
      'HTTP $method ← $statusCode $sanitizedUrl',
      metadata: meta,
      correlationId: correlationId,
    );
  }

  /// Remove sensitive query parameters from URLs
  String _sanitizeUrl(String url) {
    try {
      final uri = Uri.parse(url);
      if (uri.queryParameters.isEmpty) return url;

      final sensitiveParams = {
        'token',
        'access_token',
        'api_key',
        'apikey',
        'key',
        'secret',
        'password',
        'code',
        'session',
      };

      final sanitizedParams = uri.queryParameters.map((key, value) {
        if (sensitiveParams.contains(key.toLowerCase())) {
          return MapEntry(key, '[REDACTED]');
        }
        return MapEntry(key, value);
      });

      return uri.replace(queryParameters: sanitizedParams).toString();
    } catch (_) {
      // If URL parsing fails, return a safe version
      return url.split('?').first;
    }
  }

  // ---------------------------------------------------------------------------
  // Database Logging
  // ---------------------------------------------------------------------------

  /// Log a database operation
  void logDatabaseOperation({
    required String operation, // e.g., 'SELECT', 'INSERT', 'UPDATE', 'DELETE'
    required String table,
    Duration? duration,
    int? rowsAffected,
    String? correlationId,
    Map<String, dynamic>? params,
  }) {
    final meta = <String, dynamic>{
      'operation': operation,
      'table': table,
    };

    if (duration != null) {
      meta['duration_ms'] = duration.inMilliseconds;
    }

    if (rowsAffected != null) {
      meta['rows_affected'] = rowsAffected;
    }

    // Log param keys only, not values (values may contain user data)
    if (params != null) {
      meta['param_keys'] = params.keys.toList();
      // In debug mode only, include sanitized params
      if (!kReleaseMode) {
        meta['params'] = _sanitizer.sanitizeMap(params);
      }
    }

    final level = (duration != null && duration.inMilliseconds > 1000)
        ? LogLevel.warning
        : LogLevel.info;

    _log(
      level,
      LogCategory.database,
      'DB $operation on $table',
      metadata: meta,
      correlationId: correlationId,
    );
  }

  // ---------------------------------------------------------------------------
  // Authentication Logging
  // ---------------------------------------------------------------------------

  /// Log an authentication event
  void logAuthEvent({
    required String event, // e.g., 'login_attempt', 'login_success', 'logout'
    String? userId,
    String? method, // e.g., 'email', 'google', 'apple', 'biometric'
    bool? success,
    String? errorCode,
    String? errorMessage,
    String? correlationId,
  }) {
    final meta = <String, dynamic>{
      'event': event,
    };

    // SECURITY: Never log the actual user ID in production — use a hash or
    // anonymized identifier. For now, log only if non-null and mask it.
    if (userId != null) {
      meta['user_id_hint'] = _maskId(userId);
    }

    if (method != null) meta['method'] = method;
    if (success != null) meta['success'] = success;
    if (errorCode != null) meta['error_code'] = errorCode;

    // SECURITY: Error messages from auth providers may leak info
    if (errorMessage != null) {
      meta['error_message'] = _sanitizeAuthError(errorMessage);
    }

    // NEVER log: password, token, OTP, MFA code, etc.

    final level = success == false ? LogLevel.warning : LogLevel.info;

    _log(
      level,
      LogCategory.auth,
      'Auth: $event${success != null ? (success ? ' ✓' : ' ✗') : ''}',
      metadata: meta,
      correlationId: correlationId,
    );
  }

  /// Log token refresh (without the actual tokens)
  void logTokenRefresh({
    required bool success,
    String? errorCode,
    Duration? tokenAge,
    String? correlationId,
  }) {
    final meta = <String, dynamic>{
      'success': success,
    };

    if (errorCode != null) meta['error_code'] = errorCode;
    if (tokenAge != null) meta['token_age_minutes'] = tokenAge.inMinutes;

    _log(
      success ? LogLevel.info : LogLevel.warning,
      LogCategory.auth,
      'Token refresh ${success ? 'succeeded' : 'failed'}',
      metadata: meta,
      correlationId: correlationId,
    );
  }

  String _maskId(String id) {
    if (id.length <= 4) return '****';
    return '${id.substring(0, 2)}***${id.substring(id.length - 2)}';
  }

  String _sanitizeAuthError(String message) {
    // Remove any tokens/credentials that might appear in error messages
    return message
        .replaceAll(RegExp(r'token[=:]\s*\S+', caseSensitive: false), 'token=[REDACTED]')
        .replaceAll(RegExp(r'password[=:]\s*\S+', caseSensitive: false), 'password=[REDACTED]')
        .replaceAll(RegExp(r'Bearer\s+\S+', caseSensitive: false), 'Bearer [REDACTED]');
  }

  // ---------------------------------------------------------------------------
  // User Interaction Logging
  // ---------------------------------------------------------------------------

  /// Log a user interaction (tap, navigation, etc.)
  void logUserInteraction({
    required String action, // e.g., 'tap', 'swipe', 'navigate'
    required String target, // e.g., 'login_button', 'settings_screen'
    Map<String, dynamic>? properties,
    String? correlationId,
  }) {
    final meta = <String, dynamic>{
      'action': action,
      'target': target,
    };

    // Sanitize properties — user interactions might carry form data
    if (properties != null) {
      meta['properties'] = _sanitizer.sanitizeMap(properties);
    }

    _log(
      LogLevel.info,
      LogCategory.userInteraction,
      'User: $action → $target',
      metadata: meta,
      correlationId: correlationId,
    );
  }

  /// Log screen view
  void logScreenView({
    required String screenName,
    Map<String, dynamic>? params,
    String? correlationId,
  }) {
    _log(
      LogLevel.info,
      LogCategory.userInteraction,
      'Screen: $screenName',
      metadata: params != null ? _sanitizer.sanitizeMap(params) : null,
      correlationId: correlationId,
    );
  }

  // ---------------------------------------------------------------------------
  // General Purpose
  // ---------------------------------------------------------------------------

  void verbose(String message,
      {LogCategory category = LogCategory.general,
      Map<String, dynamic>? metadata}) {
    _log(LogLevel.verbose, category, message, metadata: metadata);
  }

  void debug(String message,
      {LogCategory category = LogCategory.general,
      Map<String, dynamic>? metadata}) {
    _log(LogLevel.debug, category, message, metadata: metadata);
  }

  void info(String message,
      {LogCategory category = LogCategory.general,
      Map<String, dynamic>? metadata}) {
    _log(LogLevel.info, category, message, metadata: metadata);
  }

  void warning(String message,
      {LogCategory category = LogCategory.general,
      Map<String, dynamic>? metadata}) {
    _log(LogLevel.warning, category, message, metadata: metadata);
  }

  void error(String message,
      {LogCategory category = LogCategory.general,
      Map<String, dynamic>? metadata,
      Object? exception,
      StackTrace? stackTrace}) {
    final meta = <String, dynamic>{
      ...?metadata,
    };

    if (exception != null) {
      meta['exception_type'] = exception.runtimeType.toString();
      // SECURITY: Don't log full exception message in production — may contain
      // sensitive data (e.g., SQL with user data, URLs with tokens)
      meta['exception'] = kReleaseMode
          ? exception.runtimeType.toString()
          : exception.toString();
    }

    if (stackTrace != null) {
      // In release mode, only include top 3 frames
      final frames = stackTrace.toString().split('\n');
      meta['stack_trace'] = kReleaseMode
          ? frames.take(3).join('\n')
          : frames.take(10).join('\n');
    }

    _log(LogLevel.error, category, message, metadata: meta);
  }

  void fatal(String message,
      {LogCategory category = LogCategory.general,
      Map<String, dynamic>? metadata,
      Object? exception,
      StackTrace? stackTrace}) {
    error(message,
        category: category,
        metadata: metadata,
        exception: exception,
        stackTrace: stackTrace);
    // Force flush all sinks on fatal
    for (final sink in _sinks) {
      sink.flush();
    }
  }

  // ---------------------------------------------------------------------------
  // Performance
  // ---------------------------------------------------------------------------

  /// Log a performance measurement
  void logPerformance({
    required String operation,
    required Duration duration,
    Map<String, dynamic>? metadata,
  }) {
    final level = duration.inMilliseconds > 3000
        ? LogLevel.warning
        : LogLevel.info;

    _log(
      level,
      LogCategory.performance,
      'Perf: $operation took ${duration.inMilliseconds}ms',
      metadata: {
        'operation': operation,
        'duration_ms': duration.inMilliseconds,
        ...?metadata,
      },
    );
  }

  /// Get the ring buffer sink for crash report data
  RingBufferLogSink? get ringBuffer {
    for (final sink in _sinks) {
      if (sink is RingBufferLogSink) return sink;
    }
    return null;
  }
}

