// HTTP Client Interceptor Example
// =============================================================================

/// Mixin for adding logging to HTTP operations
mixin HttpLoggingMixin {
  AppLogger get logger => AppLogger.instance;

  /// Wrap an HTTP call with logging
  Future<T> loggedHttpCall<T>({
    required String method,
    required String url,
    required Map<String, String>? headers,
    dynamic body,
    required Future<T> Function() execute,
    required int Function(T) getStatusCode,
    String? correlationId,
  }) async {
    final cid = correlationId ?? DateTime.now().microsecondsSinceEpoch.toString();
    final stopwatch = Stopwatch()..start();

    logger.logHttpRequest(
      method: method,
      url: url,
      headers: headers,
      body: body,
      correlationId: cid,
    );

    try {
      final response = await execute();
      stopwatch.stop();

      logger.logHttpResponse(
        method: method,
        url: url,
        statusCode: getStatusCode(response),
        duration: stopwatch.elapsed,
        correlationId: cid,
      );

      return response;
    } catch (e, st) {
      stopwatch.stop();

      logger.error(
        'HTTP $method $url failed',
        category: LogCategory.http,
        exception: e,
        stackTrace: st,
        metadata: {'duration_ms': stopwatch.elapsedMilliseconds},
      );

      rethrow;
    }
  }
}

