void exampleUsage() {
  // Initialize at app startup
  AppLogger.initialize(
    minLevel: kReleaseMode ? LogLevel.info : LogLevel.debug,
    sinks: [
      ConsoleLogSink(),
      RingBufferLogSink(maxEntries: 200),
      // RemoteLogSink(endpoint: 'https://logs.example.com/v1/ingest'),
    ],
  );

  final log = AppLogger.instance;

  // --- Auth flow logging (NO passwords or tokens logged) ---
  log.logAuthEvent(
    event: 'login_attempt',
    method: 'email',
    correlationId: 'auth-001',
  );

  log.logAuthEvent(
    event: 'login_success',
    userId: 'usr_abc123xyz',
    method: 'email',
    success: true,
    correlationId: 'auth-001',
  );

  // --- HTTP logging (headers/body sanitized) ---
  log.logHttpRequest(
    method: 'POST',
    url: 'https://api.example.com/v1/users?token=secret123',
    headers: {
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.abc.def',
      'Content-Type': 'application/json',
    },
    body: {
      'email': 'user@example.com',
      'password': 'supersecret123',
      'name': 'John Doe',
    },
    correlationId: 'req-001',
  );

  // --- Database logging ---
  log.logDatabaseOperation(
    operation: 'SELECT',
    table: 'users',
    duration: const Duration(milliseconds: 45),
    rowsAffected: 1,
    params: {'email': 'user@example.com', 'password': 'hashed_value'},
  );

  // --- User interaction ---
  log.logUserInteraction(
    action: 'tap',
    target: 'submit_order_button',
    properties: {'order_total': 49.99, 'item_count': 3},
  );

  log.logScreenView(screenName: 'ProfileScreen');

  // --- Performance ---
  log.logPerformance(
    operation: 'image_upload',
    duration: const Duration(milliseconds: 2340),
    metadata: {'file_size_kb': 1024},
  );

  // --- Error with exception ---
  try {
    throw FormatException('Invalid token format: eyJhbG...');
  } catch (e, st) {
    log.error(
      'Failed to parse auth response',
      category: LogCategory.auth,
      exception: e,
      stackTrace: st,
    );
  }
}